sys_script_include.script:
var UserInGroupCheck3 = Class.create();
UserInGroupCheck3.prototype = Object.extendsObject(AbstractAjaxProcessor, {

    // queries the Group table for selected group & check if they're a member of the group in sys_user_grmember table
    checkUserInGroup: function() {		

		var roleLabel = this.getParameter('sysparm_roleLabel');
		var userSysId = this.getParameter('sysparm_userSysId');

        // finding sys_id of group
        var gr = new GlideRecord('sys_user_group');
        gr.addQuery('name', roleLabel);
        gr.query();

        if (gr.next()) {
			// assign sys_id to roleSysId
            var roleSysId = gr.getValue('sys_id');

            // use roleSysId and user to find if a matching record exists
            var grMember = new GlideRecord('sys_user_grmember');
            grMember.addQuery('group', roleSysId);
            grMember.addQuery('user', userSysId);
            grMember.query();

			if (grMember.next()) {
				// user is in group
				gs.info("Is a member is returning true");
                return 'true';
            } else {
				// user is not in group
				gs.info("Is a member is returning false");
				return 'false';
			}
        } else {
			return 'Group doesn\'t exist or is inactive.';
		}
    },

    type: 'UserInGroupCheck3'
});
